const body = $input.first().json.body || $input.first().json;

const commits = body.commits || [];
const ref = body.ref || '';
const pusher = body.pusher?.name || body.sender?.login || '';

// Skip commits tagged with [op-sync] to prevent feedback loops
const filteredCommits = commits.filter(c => !(c.message || '').includes('[op-sync]'));

if (filteredCommits.length === 0) {
  return [];
}

// Collect all files changed across filtered commits
const allChangedFiles = new Set();
for (const commit of filteredCommits) {
  for (const f of (commit.added || [])) allChangedFiles.add(f);
  for (const f of (commit.modified || [])) allChangedFiles.add(f);
  for (const f of (commit.removed || [])) allChangedFiles.add(f);
}

// Filter to .planning/ file changes only
const planningFiles = [...allChangedFiles].filter(f => f.startsWith('.planning/'));

if (planningFiles.length === 0) {
  return [];
}

return [{
  json: {
    ref,
    pusher,
    planningFiles,
    commits: filteredCommits.map(c => ({
      id: c.id,
      message: c.message,
      timestamp: c.timestamp
    }))
  }
}];

const item = $input.first().json;
const { planningFiles, commits, ref, pusher } = item;

// Categorize each .planning/ file change
// Path patterns:
//   .planning/ROADMAP.md                                    → roadmap
//   .planning/STATE.md                                      → state
//   .planning/phases/{phaseNum}-{slug}/{planNum}-{taskNum}-PLAN.md → plan

const categorized = planningFiles.map(filePath => {
  const filename = filePath.split('/').pop() || '';

  if (filename === 'ROADMAP.md') {
    return { filePath, category: 'roadmap', phaseNum: null, planNum: null, taskNum: null };
  }

  if (filename === 'STATE.md') {
    return { filePath, category: 'state', phaseNum: null, planNum: null, taskNum: null };
  }

  // Match phases/{phaseNum}-{slug}/{planNum}-{taskNum}-PLAN.md
  const planMatch = filePath.match(/phases\/(\d+)-[^/]+\/(\d+)-(\d+)-PLAN\.md$/);
  if (planMatch) {
    return {
      filePath,
      category: 'plan',
      phaseNum: parseInt(planMatch[1], 10),
      planNum: parseInt(planMatch[2], 10),
      taskNum: parseInt(planMatch[3], 10)
    };
  }

  // Generic .planning/ file
  return { filePath, category: 'other', phaseNum: null, planNum: null, taskNum: null };
});

return [{
  json: {
    ref,
    pusher,
    categorized,
    commits
  }
}];
